{"code": "import sys

def main():
    n = int(sys.stdin.readline())
    p = list(map(int, sys.stdin.readline().split()))
    t = list(map(int, sys.stdin.readline().split()))
    max_t = max(t)
    max_cups = n + max_t
    INF = float('inf')
    dp = [INF] * (max_cups + 1)
    dp[0] = 0
    for i in range(max_cups + 1):
        for j in range(4):
            if i >= t[j]:
                if dp[i - t[j]] + p[j] < dp[i]:
                    dp[i] = dp[i - t[j]] + p[j]
    result = min(dp[n:max_cups+1])
    print(result)

if __name__ == "__main__":
    main()"}

